    int minLength(string s) {
        int n = s.length();
        vector<int> dp(n, n); // dp[i] stores the minimum length after removing substring of length i
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (s[j] == 'A' && s[i] == 'B') {
                    dp[i] = min(dp[i], dp[j] + 1);
                }
                if (s[j] == 'A' && s[i] == 'C') {
                    dp[i] = min(dp[i], dp[j] + 1);
                }
                if (s[j] == 'B' && s[i] == 'A') {
                    dp[i] = min(dp[i], dp[j] + 1);
                }
                if (s[j] == 'C' && s[i] == 'B') {
                    dp[i] = min(dp[i], dp[j] + 1);
                }
            }
        }
    }
    int result = dp[n-1];
    return result;
}
